import jakarta.servlet.*;
import jakarta.servlet.http.*;

public class ConfigServlet extends HttpServlet {
 private String defaultTheme;

 public void init() {
 defaultTheme = getInitParameter("defaultTheme");
 }

 protected void doGet(HttpServletRequest request, HttpServletResponse response) 
 throws ServletException, IOException {
 String theme = request.getParameter("theme") != null 
 ? request.getParameter("theme") 
 : defaultTheme;
 request.setAttribute("selectedTheme", theme);
 request.getRequestDispatcher("/prefs.jsp").forward(request, response);
 }
}
